-static uint32_t CountTensorListLen(gert::TilingContext *context, int descIndex)
-{
-    int count = 0;
-    for (uint32_t i = 0; i < MAX_TENSOR_COUNT; i++) {
-        auto tensorElement = context->GetDynamicInputTensor(descIndex, i);
-        if (tensorElement == nullptr) {
